import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getFeatured, getCategories } from '../services/api';
import ProductCard from '../components/ProductCard';

const Home = () => {
  const [featured, setFeatured] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  // Fallback featured products if the API is empty
  const mockProducts = [
    { _id: '1', name: 'Minimalist Oak Chair', price: 299, image: 'https://images.unsplash.com/photo-1567538096630-e0c55bd6374c?w=500', category: 'Living' },
    { _id: '2', name: 'Sage Velvet Sofa', price: 899, image: 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=500', category: 'Living' },
    { _id: '3', name: 'Floating Bed Frame', price: 1200, image: 'https://images.unsplash.com/photo-1505693419148-ad3b471e804c?w=500', category: 'Bedroom' },
    { _id: '4', name: 'Ceramic Table Lamp', price: 150, image: 'https://images.unsplash.com/photo-1534073828943-f801091bb18c?w=500', category: 'Accessories' }
  ];

  useEffect(() => {
    const load = async () => {
      try {
        const [f, c] = await Promise.all([getFeatured(), getCategories()]);
        setFeatured(f.data?.length > 0 ? f.data : mockProducts);
        setCategories(c.data || []);
      } catch (e) { 
        console.error(e);
        setFeatured(mockProducts); // Load mocks on error so UI isn't empty
      }
      finally { setLoading(false); }
    };
    load();
  }, []);

  const colors = {
    navy: '#4a5d53',      // Forest Green
    gold: '#c2b2a3',      // Muted Sage/Gold
    cream: '#e2e4e1',     // Off-white background
    white: '#ffffff',
    grayText: '#8b9691'   
  };

  return (
    <div className="home" style={{ backgroundColor: colors.cream }}>
      {/* Hero Section with Background Image */}
      <section className="hero" style={{
        backgroundImage: `linear-gradient(rgba(74, 93, 83, 0.8), rgba(74, 93, 83, 0.8)), url("https://images.unsplash.com/photo-1618221195710-dd6b41faaea6?w=1600")`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        padding: '100px 40px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        minHeight: '85vh',
        position: 'relative',
        overflow: 'hidden'
      }}>
        <div className="hero-content" style={{ color: '#ffffff', maxWidth: '600px', zIndex: 1 }}>
          <p style={{
            color: colors.gold,
            fontSize: '14px',
            textTransform: 'uppercase',
            letterSpacing: '4px',
            marginBottom: '15px',
            fontWeight: '600'
          }}>New Collection 2026</p>

          <h1 style={{
            fontSize: 'clamp(2.5rem, 5vw, 4rem)',
            fontWeight: '800',
            marginBottom: '20px',
            lineHeight: '1.1'
          }}>Elevate Your Home with <span style={{ color: colors.gold }}>SAS Furniture</span></h1>

          <p style={{
            color: 'rgba(255,255,255,0.8)',
            fontSize: '1.2rem',
            lineHeight: '1.6',
            marginBottom: '40px',
            maxWidth: '500px'
          }}>Experience the perfect blend of sustainable materials and modern designer aesthetics.</p>

          <div style={{ display: 'flex', gap: '20px' }}>
            <Link to="/products" style={{
              background: colors.gold,
              color: colors.navy,
              padding: '14px 35px',
              borderRadius: '4px',
              textDecoration: 'none',
              fontWeight: '700',
              transition: '0.3s'
            }}>Shop Collection</Link>
          </div>
        </div>
      </section>

      {/* Categories */}
      <section style={{ padding: '100px 40px', maxWidth: '1400px', margin: '0 auto' }}>
        <h2 style={{ fontSize: '2.5rem', color: colors.navy, marginBottom: '40px', textAlign: 'center' }}>Shop by Category</h2>
        <div className="category-grid" style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
          gap: '20px'
        }}>
          {['Living', 'Bedroom', 'Dining', 'Office', 'Decor', 'Sale'].map(cat => (
            <Link to={`/products?category=${cat}`} key={cat} style={{
              position: 'relative',
              height: '250px',
              borderRadius: '8px',
              overflow: 'hidden',
              textDecoration: 'none',
              display: 'block'
            }}>
              <img src={`https://images.unsplash.com/photo-1616489953149-8033626e25a2?w=400&q=80`} alt={cat} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
              <div style={{
                position: 'absolute', inset: 0, 
                background: 'rgba(74, 93, 83, 0.4)', 
                display: 'flex', alignItems: 'center', justifyContent: 'center'
              }}>
                <span style={{ color: 'white', fontSize: '1.5rem', fontWeight: 'bold' }}>{cat}</span>
              </div>
            </Link>
          ))}
        </div>
      </section>

      {/* Featured Products - Now populated */}
      <section style={{ padding: '80px 40px', maxWidth: '1400px', margin: '0 auto', backgroundColor: colors.white, borderRadius: '20px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '50px' }}>
          <h2 style={{ fontSize: '2.5rem', fontWeight: '800', color: colors.navy }}>Featured Pieces</h2>
          <Link to="/products" style={{ color: colors.gold, fontWeight: '700', textDecoration: 'none' }}>Browse All →</Link>
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: '100px' }}>
            <div className="spinner" style={{ width: '40px', height: '40px', border: `4px solid ${colors.gold}`, borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto' }}></div>
          </div>
        ) : (
          <div className="products-grid" style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
            gap: '40px'
          }}>
            {featured.map(p => (
              <div key={p._id} style={{ transition: 'transform 0.3s' }} onMouseOver={e => e.currentTarget.style.transform = 'translateY(-10px)'} onMouseOut={e => e.currentTarget.style.transform = 'translateY(0)'}>
                <ProductCard product={p} />
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Newsletter Promo */}
      <section style={{ background: colors.navy, color: '#ffffff', textAlign: 'center', padding: '100px 40px', marginTop: '100px' }}>
        <h2 style={{ fontSize: '2.5rem', marginBottom: '20px' }}>Join the SAS Inner Circle</h2>
        <p style={{ color: colors.gold, marginBottom: '40px' }}>Get 20% off your first handcrafted piece with code <strong>WELCOME20</strong></p>
        <Link to="/register" style={{
          background: colors.gold,
          color: colors.navy,
          padding: '15px 40px',
          borderRadius: '4px',
          textDecoration: 'none',
          fontWeight: '700'
        }}>Sign Up Now</Link>
      </section>

      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        .hero-content h1 { text-shadow: 0 4px 10px rgba(0,0,0,0.2); }
      `}</style>
    </div>
  );
};

export default Home;
